package com.example.patterns;

public class RestaurantMeal {
    private String item;
    private String drink;
    private String appetizer;
    private String dessert;
    private boolean isVeg;
    private int portionSize;
    private double totalPrice;

    private RestaurantMeal(Builder builder) {
        this.item = builder.item;
        this.drink = builder.drink;
        this.appetizer = builder.appetizer;
        this.dessert = builder.dessert;
        this.isVeg = builder.isVeg;
        this.portionSize = builder.portionSize;
        this.totalPrice = builder.totalPrice;
    }

    public static class Builder {
        private String item;
        private String drink;
        private String appetizer;
        private String dessert;
        private boolean isVeg = false;
        private int portionSize = 1;
        private double totalPrice = 0.0;

        public Builder addItem(String item) {
            this.item = item;
            return this;
        }

        public Builder addDrink(String drink) {
            this.drink = drink;
            return this;
        }

        public Builder addAppetizer(String appetizer) {
            this.appetizer = appetizer;
            return this;
        }

        public Builder addDessert(String dessert) {
            this.dessert = dessert;
            return this;
        }

        public Builder makeVeg(boolean isVeg) {
            this.isVeg = isVeg;
            return this;
        }

        public Builder setPortion(int portionSize) {
            this.portionSize = portionSize;
            return this;
        }

        public Builder calculatePrice() {
            double price = 0;
            if (item != null) price += getItemPrice(item);
            if (drink != null) price += getDrinkPrice(drink);
            if (appetizer != null) price += getAppetizerPrice(appetizer);
            if (dessert != null) price += getDessertPrice(dessert);
            this.totalPrice = price * portionSize;
            return this;
        }

        public RestaurantMeal build() {
            if (item == null) {
                throw new IllegalArgumentException("Item is required");
            }
            calculatePrice();
            return new RestaurantMeal(this);
        }

        private double getItemPrice(String item) { /* ... */ return 10.0; }
        private double getDrinkPrice(String drink) { /* ... */ return 3.0; }
        private double getAppetizerPrice(String app) { /* ... */ return 5.0; }
        private double getDessertPrice(String dessert) { /* ... */ return 4.0; }
    }
}

