package com.example.patterns;

import java.util.function.BiFunction;

@FunctionalInterface
public interface PricingStrategy {
    double calculate(double basePrice, CustomerContext context);
}

class CustomerContext {
    private final String customerId;
    private final int purchaseCount;
    private final MembershipLevel membership;
    private final boolean isFirstPurchase;

    public enum MembershipLevel {
        BASIC, PREMIUM, VIP
    }

    public CustomerContext(String customerId, int purchaseCount,
                          MembershipLevel membership, boolean isFirstPurchase) {
        this.customerId = customerId;
        this.purchaseCount = purchaseCount;
        this.membership = membership;
        this.isFirstPurchase = isFirstPurchase;
    }

    // getters...
}

public class PricingEngine {
    private final PricingStrategy defaultStrategy;

    public PricingEngine(PricingStrategy defaultStrategy) {
        this.defaultStrategy = defaultStrategy;
    }

    public double calculateFinalPrice(double basePrice, CustomerContext context) {
        return defaultStrategy.calculate(basePrice, context);
    }

    // Built-in strategies as lambdas
    public static PricingStrategy volumeDiscount = (price, ctx) -> {
        if (ctx.getPurchaseCount() >= 10) return price * 0.8;
        if (ctx.getPurchaseCount() >= 5) return price * 0.9;
        return price;
    };

    public static PricingStrategy vipDiscount = (price, ctx) -> {
        if (ctx.getMembership() == CustomerContext.MembershipLevel.VIP) return price * 0.7;
        if (ctx.getMembership() == CustomerContext.MembershipLevel.PREMIUM) return price * 0.85;
        return price;
    };

    public static PricingStrategy newCustomerDiscount = (price, ctx) -> {
        return ctx.isFirstPurchase() ? price * 0.9 : price;
    };

    public static PricingStrategy combine(PricingStrategy... strategies) {
        return (price, context) -> {
            double result = price;
            for (PricingStrategy strategy : strategies) {
                result = strategy.calculate(result, context);
            }
            return Math.max(result, 0);
        };
    }
}

package com.example.patterns;

import java.util.Observable;
import java.util.Observer;

public class StockMarket extends Observable {
    private String stockSymbol;
    private double currentPrice;

    public StockMarket(String stockSymbol) {
        this.stockSymbol = stockSymbol;
    }

    public void setPrice(double newPrice) {
        if (this.currentPrice != newPrice) {
            this.currentPrice = newPrice;
            setChanged();
            notifyObservers(newPrice);
        }
    }

    public double getCurrentPrice() {
        return currentPrice;
    }

    public String getStockSymbol() {
        return stockSymbol;
    }
}

public class StockPriceAlert implements Observer {
    private final String investorName;
    private final double thresholdPrice;
    private final AlertType alertType;

    public enum AlertType {
        ABOVE, BELOW, EXACTLY
    }

    public StockPriceAlert(String investorName, double thresholdPrice, AlertType alertType) {
        this.investorName = investorName;
        this.thresholdPrice = thresholdPrice;
        this.alertType = alertType;
    }

    @Override
    public void update(Observable o, Object arg) {
        double price = (double) arg;
        boolean shouldAlert = false;

        switch (alertType) {
            case ABOVE:
                shouldAlert = price > thresholdPrice;
                break;
            case BELOW:
                shouldAlert = price < thresholdPrice;
                break;
            case EXACTLY:
                shouldAlert = Math.abs(price - thresholdPrice) < 0.01;
                break;
        }

        if (shouldAlert) {
            System.out.printf("%s: %s is now $%.2f (threshold: $%.2f, type: %s)%n",
                    investorName, ((StockMarket) o).getStockSymbol(), price,
                    thresholdPrice, alertType);
        }
    }
}

