package com.example.patterns.payment;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class PaymentFactory {

    private final Map<String, PaymentProcessor> processorMap = new ConcurrentHashMap<>();

    @Autowired
    private Map<String, PaymentProcessor> processors;

    @PostConstruct
    public void init() {
        processors.forEach(processorMap::put);
    }

    public PaymentProcessor getProcessor(String paymentType) {
        PaymentProcessor processor = processorMap.get(paymentType);
        if (processor == null) {
            throw new IllegalArgumentException("Unsupported payment type: " + paymentType);
        }
        return processor;
    }

    public boolean supportsPaymentType(String paymentType) {
        return processorMap.containsKey(paymentType);
    }
}

public interface PaymentProcessor {
    PaymentResult processPayment(PaymentRequest request);
    String getPaymentType();
}

@Component
public class CreditCardProcessor implements PaymentProcessor {
    @Override
    public PaymentResult processPayment(PaymentRequest request) {
        // Process credit card payment
        return new PaymentResult(true, "CC-" + request.getTransactionId());
    }

    @Override
    public String getPaymentType() {
        return "CREDIT_CARD";
    }
}

@Component
public class PayPalProcessor implements PaymentProcessor {
    @Override
    public PaymentResult processPayment(PaymentRequest request) {
        // Process PayPal payment
        return new PaymentResult(true, "PP-" + request.getTransactionId());
    }

    @Override
    public String getPaymentType() {
        return "PAYPAL";
    }
}

@Component
public class BankTransferProcessor implements PaymentProcessor {
    @Override
    public PaymentResult processPayment(PaymentRequest request) {
        // Process bank transfer
        return new PaymentResult(true, "BT-" + request.getTransactionId());
    }

    @Override
    public String getPaymentType() {
        return "BANK_TRANSFER";
    }
}

package com.example.patterns.export;

import java.io.IOException;
import java.util.List;

public abstract class DataExporter<T> {

    protected abstract List<T> fetchData();
    protected abstract String formatRecord(T record);
    protected abstract void initializeOutput() throws IOException;
    protected abstract void finalizeOutput() throws IOException;

    public void export(String outputPath) throws IOException {
        System.out.println("Starting data export to: " + outputPath);

        initializeOutput();

        try {
            List<T> data = fetchData();
            System.out.println("Fetched " + data.size() + " records");

            for (T record : data) {
                String formatted = formatRecord(record);
                writeRecord(formatted);
            }

            finalizeOutput();
            System.out.println("Export completed successfully");
        } catch (Exception e) {
            System.err.println("Export failed: " + e.getMessage());
            throw e;
        }
    }

    protected abstract void writeRecord(String record) throws IOException;

    protected void logProgress(int current, int total) {
        double percentage = (double) current / total * 100;
        System.out.printf("Progress: %.1f%% (%d/%d)%n", percentage, current, total);
    }
}

public class CSVExporter extends DataExporter<Customer> {
    private java.io.Writer writer;

    @Override
    protected List<Customer> fetchData() {
        return customerRepository.findAll();
    }

    @Override
    protected String formatRecord(Customer customer) {
        return String.join(",", customer.getId(), customer.getName(), customer.getEmail());
    }

    @Override
    protected void initializeOutput() throws IOException {
        writer = new java.io.BufferedWriter(new java.io.FileWriter(outputPath));
        writer.write("id,name,email");
        writer.newLine();
    }

    @Override
    protected void finalizeOutput() throws IOException {
        writer.flush();
        writer.close();
    }

    @Override
    protected void writeRecord(String record) throws IOException {
        writer.write(record);
        writer.newLine();
    }
}

public class JSONExporter extends DataExporter<Customer> {
    private java.io.Writer writer;

    @Override
    protected List<Customer> fetchData() {
        return customerRepository.findAll();
    }

    @Override
    protected String formatRecord(Customer customer) {
        return "{\"id\":\"" + customer.getId() + "\",\"name\":\"" + customer.getName() + "\"}";
    }

    @Override
    protected void initializeOutput() throws IOException {
        writer = new java.io.BufferedWriter(new java.io.FileWriter(outputPath));
        writer.write("[");
    }

    @Override
    protected void finalizeOutput() throws IOException {
        writer.write("]");
        writer.flush();
        writer.close();
    }

    @Override
    protected void writeRecord(String record) throws IOException {
        writer.write(record);
        writer.write(",");
    }
}

package com.example.patterns.proxy;

import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

public interface UserService {
    User findById(String id);
    List<User> findAll();
    User createUser(User user);
    void deleteUser(String id);
}

public class UserServiceImpl implements UserService {
    private final UserRepository repository;

    public UserServiceImpl(UserRepository repository) {
        this.repository = repository;
    }

    @Override
    public User findById(String id) {
        return repository.findById(id).orElse(null);
    }

    @Override
    public List<User> findAll() {
        return repository.findAll();
    }

    @Override
    public User createUser(User user) {
        return repository.save(user);
    }

    @Override
    public void deleteUser(String id) {
        repository.delete(id);
    }
}

public class AuditProxyHandler implements InvocationHandler {
    private final Object target;
    private final AuditLogger auditLogger;

    public AuditProxyHandler(Object target, AuditLogger auditLogger) {
        this.target = target;
        this.auditLogger = auditLogger;
    }

    @Override
    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
        String methodName = method.getName();
        long startTime = System.currentTimeMillis();

        auditLogger.log("START", "UserService." + methodName, args);

        try {
            Object result = method.invoke(target, args);
            long duration = System.currentTimeMillis() - startTime;

            auditLogger.log("SUCCESS", "UserService." + methodName, 
                new Object[]{duration + "ms"});
            return result;
        } catch (Exception e) {
            auditLogger.log("ERROR", "UserService." + methodName, e.getMessage());
            throw e;
        }
    }
}

public class SecureUserServiceProxy {
    public static UserService createProxy(UserService userService) {
        return (UserService) Proxy.newProxyInstance(
            UserService.class.getClassLoader(),
            new Class<?>[]{UserService.class},
            new AuditProxyHandler(userService, new AuditLogger())
        );
    }
}

package com.example.patterns.validation;

import java.util.ArrayList;
import java.util.List;

public interface Validator {
    boolean validate(RequestContext context);
    String getName();
    void setNext(Validator next);
}

public abstract class AbstractValidator implements Validator {
    protected Validator next;

    @Override
    public void setNext(Validator next) {
        this.next = next;
    }

    @Override
    public boolean validate(RequestContext context) {
        if (!isValid(context)) {
            context.addError(getName(), getErrorMessage());
            return false;
        }
        if (next != null) {
            return next.validate(context);
        }
        return true;
    }

    protected abstract boolean isValid(RequestContext context);
    protected abstract String getErrorMessage();
}

public class EmailValidator extends AbstractValidator {
    @Override
    protected boolean isValid(RequestContext context) {
        String email = context.getEmail();
        return email != null && email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$");
    }

    @Override
    protected String getErrorMessage() {
        return "Invalid email format";
    }

    @Override
    public String getName() {
        return "EmailValidator";
    }
}

public class PasswordValidator extends AbstractValidator {
    @Override
    protected boolean isValid(RequestContext context) {
        String password = context.getPassword();
        return password != null && password.length() >= 8
            && password.matches(".*[A-Z].*")
            && password.matches(".*[0-9].*");
    }

    @Override
    protected String getErrorMessage() {
        return "Password must be at least 8 characters with uppercase and digit";
    }

    @Override
    public String getName() {
        return "PasswordValidator";
    }
}

public class AgeValidator extends AbstractValidator {
    @Override
    protected boolean isValid(RequestContext context) {
        return context.getAge() != null && context.getAge() >= 18;
    }

    @Override
    protected String getErrorMessage() {
        return "Must be at least 18 years old";
    }

    @Override
    public String getName() {
        return "AgeValidator";
    }
}

public class ValidationChain {
    private final List<Validator> validators = new ArrayList<>();

    public ValidationChain addValidator(Validator validator) {
        validators.add(validator);
        return this;
    }

    public ValidationResult validate(RequestContext context) {
        ValidationResult result = new ValidationResult();
        for (Validator validator : validators) {
            if (!validator.validate(context)) {
                result.addErrors(context.getErrors());
            }
        }
        result.setSuccess(context.getErrors().isEmpty());
        return result;
    }
}

package com.example.patterns.adapter;

public interface PaymentGateway {
    PaymentResponse charge(PaymentRequest request);
    PaymentResponse refund(String transactionId, double amount);
    TransactionStatus getStatus(String transactionId);
}

// Legacy system with incompatible API
public class LegacyPaymentSystem {
    public String submitOrder(String itemName, int quantity, double unitPrice, String cardNumber) {
        // Legacy system returns order ID like "ORD-12345"
        return "ORD-" + System.currentTimeMillis();
    }

    public String cancelOrder(String orderId) {
        return "CANCELLED";
    }

    public String getOrderStatus(String orderId) {
        return "PROCESSED";
    }
}

public class LegacyPaymentAdapter implements PaymentGateway {
    private final LegacyPaymentSystem legacySystem;

    public LegacyPaymentAdapter(LegacyPaymentSystem legacySystem) {
        this.legacySystem = legacySystem;
    }

    @Override
    public PaymentResponse charge(PaymentRequest request) {
        String legacyOrderId = legacySystem.submitOrder(
            request.getItemName(),
            request.getQuantity(),
            request.getAmount(),
            request.getCardNumber()
        );

        return new PaymentResponse(
            true,
            legacyOrderId,
            request.getAmount(),
            "CHARGED"
        );
    }

    @Override
    public PaymentResponse refund(String transactionId, double amount) {
        String status = legacySystem.cancelOrder(transactionId);
        return new PaymentResponse(
            "CANCELLED".equals(status),
            transactionId,
            amount,
            status
        );
    }

    @Override
    public TransactionStatus getStatus(String transactionId) {
        String legacyStatus = legacySystem.getOrderStatus(transactionId);
        return mapLegacyStatus(legacyStatus);
    }

    private TransactionStatus mapLegacyStatus(String legacyStatus) {
        switch (legacyStatus) {
            case "PROCESSED": return TransactionStatus.COMPLETED;
            case "CANCELLED": return TransactionStatus.CANCELLED;
            case "PENDING": return TransactionStatus.PENDING;
            default: return TransactionStatus.UNKNOWN;
        }
    }
}
